from langgraph.errors import GraphRecursionError

config = {"recursion_limit": 15}
try:
    result = app.invoke(
        {"query": "research question", "retry_count": 0, "tool_calls": [], "answer": "", "error": ""},
        config=config,
    )
except GraphRecursionError:
    result = {"answer": "Could not complete within the iteration limit"}

# Guard inside the router function is equally valid:
def route_with_limit(state) -> Literal["tools", "__end__"]:
    if state.get("retry_count", 0) >= 5:
        return "__end__"   # hard stop
    return "tools" if state.get("tool_calls") else "__end__"

from typing import Literal

def route_after_eval(
    state,
) -> Literal["refine", "human_review", "escalation_handler", "__end__"]:
    score = state.get("quality_score", 0)
    attempts = state.get("attempts", 0)
    if score >= 0.9:
        return "__end__"
    if score >= 0.6:
        return "human_review"
    if attempts >= 3:
        return "escalation_handler"
    return "refine"

graph.add_conditional_edges(
    "evaluator",
    route_after_eval,
    {
        "refine": "refine",
        "human_review": "human_review",
        "escalation_handler": "escalation_handler",
        "__end__": END,
    },
)

import pytest
from langgraph.checkpoint.memory import MemorySaver

# Unit-test the router in isolation
def test_route_to_tools():
    state = {"query": "q", "tool_calls": [{"name": "search"}], "answer": "", "error": "", "retry_count": 0}
    assert route_after_planner(state) == "tools"

def test_route_to_respond():
    state = {"query": "q", "tool_calls": [], "answer": "done", "error": "", "retry_count": 0}
    assert route_after_planner(state) == "respond"

def test_route_to_retry():
    state = {"query": "q", "tool_calls": [], "answer": "", "error": "rate limit", "retry_count": 1}
    assert route_after_planner(state) == "retry"

# Integration: assert node execution order via stream_mode="updates"
def test_tool_branch_fires(app):
    steps = list(app.stream(
        {"query": "capital of France", "tool_calls": [], "answer": "", "error": "", "retry_count": 0},
        stream_mode="updates",
    ))
    node_sequence = [list(step.keys())[0] for step in steps]
    assert "planner" in node_sequence
    if "tools" in node_sequence:
        # tools must come after the first planner step
        assert node_sequence.index("tools") > node_sequence.index("planner")
